import{_ as s,c as t,o as e,a4 as a}from"./chunks/framework.BxjRYGQi.js";const g=JSON.parse('{"title":"Common Robot Control Interfaces","description":"","frontmatter":{},"headers":[],"relativePath":"en/02-quick-start/07-Service_interface.md","filePath":"en/02-quick-start/07-Service_interface.md"}'),r={name:"en/02-quick-start/07-Service_interface.md"};function l(n,i,o,h,d,k){return e(),t("div",{"data-pagefind-body":!0},i[0]||(i[0]=[a('<h1 id="common-robot-control-interfaces" tabindex="-1">Common Robot Control Interfaces <a class="header-anchor" href="#common-robot-control-interfaces" aria-label="Permalink to “Common Robot Control Interfaces”">​</a></h1><p>Provides commonly used robot control interfaces, including moving to specified positions, IO control, program execution control, and servo power on/off control,Emergency stop.</p><blockquote><p><strong>Note:</strong></p><ul><li><code>robot_name</code> defaults to <code>&quot;C5A&quot;</code> .</li><li>Optional values: <code>C7A</code> , <code>C12A</code> , <code>C16A</code> .</li></ul></blockquote><h2 id="robot-end-effector-movement-to-target-position" tabindex="-1">Robot End-effector Movement to Target Position <a class="header-anchor" href="#robot-end-effector-movement-to-target-position" aria-label="Permalink to “Robot End-effector Movement to Target Position”">​</a></h2><h3 id="interface-name" tabindex="-1">Interface Name <a class="header-anchor" href="#interface-name" aria-label="Permalink to “Interface Name”">​</a></h3><ul><li><code>gbt_interface/action/MoveToPose</code></li></ul><h3 id="usage-method" tabindex="-1">Usage Method <a class="header-anchor" href="#usage-method" aria-label="Permalink to “Usage Method”">​</a></h3><p>Start service:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ros2</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> launch</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gbt_driver</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gbt_service_server.launch.py</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> robot_name:={robot_name}</span></span></code></pre></div><p>Simulate sending target position request:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ros2</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> action</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> send_goal</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /gbt_driver/move_to_pose</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gbt_interface/action/MoveToPose</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;{ x: 400.0, y: -200.0, z: 500.0, a: 100.0, b: 30.0, c: 110, vel: 1, acc: 1 }&quot;</span></span></code></pre></div><h2 id="io-readwrite" tabindex="-1">IO Read/Write <a class="header-anchor" href="#io-readwrite" aria-label="Permalink to “IO Read/Write”">​</a></h2><blockquote><p><strong>Note</strong>: Please configure the I/O mapping before using the I/O control function.</p></blockquote><ul><li><strong>Interface Name</strong>: <code>gbt_interface/srv/IO</code></li><li><strong>Start Service</strong>:</li></ul><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ros2</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> launch</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gbt_driver</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gbt_service_server.launch.py</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> robot_name:={robot_name}</span></span></code></pre></div><ul><li><strong>Set IO Port Status</strong>:</li></ul><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ros2</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> service</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> call</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /gbt_driver/service_server/io</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gbt_interface/srv/IO</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;{signal_type: 2, signal_port: 1, signal_value: 1, command: set}&quot;</span></span></code></pre></div><ul><li><strong>Get IO Port Status</strong>:</li></ul><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ros2</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> service</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> call</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /gbt_driver/service_server/io</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gbt_interface/srv/IO</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;{signal_type: 2, signal_port: 1, command: get}&quot;</span></span></code></pre></div><h3 id="io-type-table" tabindex="-1">IO TYPE Table <a class="header-anchor" href="#io-type-table" aria-label="Permalink to “IO TYPE Table”">​</a></h3><p>Here’s the enum list formatted as an English markdown table:</p><table tabindex="0"><thead><tr><th>Enum</th><th>Value</th><th>Description</th></tr></thead><tbody><tr><td>DI</td><td>1</td><td>Signal Type</td></tr><tr><td>DO</td><td>2</td><td>Digital Input</td></tr><tr><td>UI</td><td>3</td><td>Digital Output</td></tr><tr><td>UO</td><td>4</td><td>Proprietary Input</td></tr><tr><td>RI</td><td>5</td><td>Proprietary Output</td></tr><tr><td>RO</td><td>6</td><td>Arm Input</td></tr><tr><td>GI</td><td>7</td><td>Arm Output</td></tr><tr><td>GO</td><td>8</td><td>Group Input</td></tr><tr><td>TAI</td><td>9</td><td>Wrist Analog Input</td></tr><tr><td>TDI</td><td>10</td><td>Wrist Digital Input</td></tr><tr><td>TDO</td><td>11</td><td>Wrist Digital Output</td></tr><tr><td>AI</td><td>12</td><td>Analog Input</td></tr><tr><td>AO</td><td>13</td><td>Analog Output</td></tr></tbody></table><h2 id="program-execution-control" tabindex="-1">Program Execution Control <a class="header-anchor" href="#program-execution-control" aria-label="Permalink to “Program Execution Control”">​</a></h2><ul><li><strong>Interface Name</strong>: <code>gbt_interface/srv/ProgramControl</code></li><li><strong>Start Service</strong>:</li></ul><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ros2</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> launch</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gbt_driver</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gbt_service_server.launch.py</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> robot_name:={robot_name}</span></span></code></pre></div><ul><li><strong>Start Program</strong>:</li></ul><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ros2</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> service</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> call</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /gbt_driver/service_server/program_control</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gbt_interface/srv/ProgramControl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;{command: &#39;start&#39;, program_name: &#39;test&#39;}&quot;</span></span></code></pre></div><p>To pause, resume or stop programs, replace the <code>command</code> parameter with:</p><ul><li><code>pause</code> : Pause program</li><li><code>resume</code> : Resume program</li><li><code>stop</code> : Stop program</li></ul><h2 id="servo-power-control" tabindex="-1">Servo Power Control <a class="header-anchor" href="#servo-power-control" aria-label="Permalink to “Servo Power Control”">​</a></h2><ul><li><strong>Interface Name</strong>: <code>gbt_interface/srv/Servo</code></li><li><strong>Start Service</strong>:</li></ul><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ros2</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> launch</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gbt_driver</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gbt_service_server.launch.py</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> robot_name:={robot_name}</span></span></code></pre></div><ul><li><strong>Servo Motor Power On</strong>:</li></ul><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ros2</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> service</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> call</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /gbt_driver/service_server/servo_power</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gbt_interface/srv/Servo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;{servo_on: true}&quot;</span></span></code></pre></div><p>To power off the servo motor, set <code>servo_on</code> parameter to <code>false</code> .</p><h2 id="emergency-stop" tabindex="-1">Emergency Stop <a class="header-anchor" href="#emergency-stop" aria-label="Permalink to “Emergency Stop”">​</a></h2><ul><li><strong>Interface Name</strong>: <code>gbt_interface/srv/EmergencyStop</code></li><li><strong>Interface Description</strong>: Controls the emergency stop state of the robotic arm</li><li><strong>Start Service</strong>:<div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ros2</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> launch</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gbt_driver</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gbt_service_server.launch.py</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> robot_name:={robot_name}</span></span></code></pre></div></li><li><strong>Usage Example</strong>:<div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ros2</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> service</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> call</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /gbt_driver/service_server/emergency_stop</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gbt_interface/srv/EmergencyStop</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;{}&quot;</span></span></code></pre></div></li></ul><h2 id="led-switch" tabindex="-1">LED Switch <a class="header-anchor" href="#led-switch" aria-label="Permalink to “LED Switch”">​</a></h2><ul><li><strong>Interface Name</strong>: <code>gbt_interface/srv/LED</code></li><li><strong>Interface Description</strong>: This interface is used to control the LED status of the robotic arm</li><li><strong>Start Service</strong>:<div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ros2</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> launch</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gbt_driver</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gbt_service_server.launch.py</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> robot_name:={robot_name}</span></span></code></pre></div></li><li><strong>Usage Example</strong>:<div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ros2</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> service</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> call</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /gbt_driver/service_server/led</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gbt_interface/srv/LED</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;{led_on: true}&quot;</span></span></code></pre></div></li></ul>',39)]))}const c=s(r,[["render",l]]);export{g as __pageData,c as default};
